# Requirement: Online Shopping System
# - Users can browse products, add to cart, place orders
# - Products have categories, prices, inventory
# - Orders contain multiple items, have payment and shipping status

from abc import ABC, abstractmethod
from datetime import datetime
from typing import List

# Entity Classes (Core Domain Objects)
class Product:
    def __init__(self, product_id, name, price, category, stock):
        self.product_id = product_id
        self.name = name
        self.price = price
        self.category = category
        self.stock = stock

    def is_available(self):
        return self.stock > 0

class Category:
    def __init__(self, category_id, name, parent_category=None):
        self.category_id = category_id
        self.name = name
        self.parent_category = parent_category
        self.products = []

# User Management
class User(ABC):
    def __init__(self, user_id, email, password):
        self.user_id = user_id
        self.email = email
        self._password = password  # Encapsulated

    @abstractmethod
    def login(self):
        pass

class Customer(User):
    def __init__(self, user_id, email, password, name, address):
        super().__init__(user_id, email, password)
        self.name = name
        self.address = address
        self.cart = Cart()
        self.orders = []

    def login(self):
        return f"Customer {self.name} logged in"

# Cart and Order Management
class CartItem:
    def __init__(self, product, quantity):
        self.product = product
        self.quantity = quantity

    def get_subtotal(self):
        return self.product.price * self.quantity

class Cart:
    def __init__(self):
        self.items = []

    def add_item(self, product, quantity):
        for item in self.items:
            if item.product.product_id == product.product_id:
                item.quantity += quantity
                return
        self.items.append(CartItem(product, quantity))

    def get_total(self):
        return sum(item.get_subtotal() for item in self.items)

class Order:
    def __init__(self, order_id, customer):
        self.order_id = order_id
        self.customer = customer
        self.items = []
        self.status = "PENDING"
        self.created_at = datetime.now()

    def place_order(self):
        self.status = "PLACED"
        print(f"Order {self.order_id} placed successfully!")

# Service Layer (Business Logic)
class OrderService:
    def __init__(self):
        self.orders = []

    def create_order(self, customer):
        if not customer.cart.items:
            return None
        order = Order(f"ORD-{len(self.orders)+1:04d}", customer)
        order.items = customer.cart.items.copy()
        customer.orders.append(order)
        self.orders.append(order)
        customer.cart.items = []  # Clear cart
        return order

# Demonstration
product1 = Product("P001", "Laptop", 50000, "Electronics", 10)
product2 = Product("P002", "Mouse", 500, "Electronics", 50)
customer = Customer("U001", "alice@email.com", "pass123", "Alice", "Delhi")
customer.login()
customer.cart.add_item(product1, 1)
customer.cart.add_item(product2, 2)
print(f"Cart Total: ₹{customer.cart.get_total()}")
order_service = OrderService()
order_service.create_order(customer)

# Advanced Requirement: Payment Processing System
# - Support multiple payment methods (Credit Card, UPI, Wallet)
# - Send notifications to users after payment
# - Apply different discount strategies based on user type

from abc import ABC, abstractmethod
from typing import List
import datetime

# ==================== STRATEGY PATTERN ====================
# Requirement: Different discount calculation strategies

class DiscountStrategy(ABC):
    @abstractmethod
    def calculate(self, amount: float) -> float:
        pass

class RegularCustomerDiscount(DiscountStrategy):
    def calculate(self, amount: float) -> float:
        return amount * 0.95  # 5% discount

class PremiumCustomerDiscount(DiscountStrategy):
    def calculate(self, amount: float) -> float:
        return amount * 0.90  # 10% discount

class FestivalDiscount(DiscountStrategy):
    def calculate(self, amount: float) -> float:
        return amount * 0.80  # 20% discount

# ==================== FACTORY PATTERN ====================
# Requirement: Support multiple payment methods

class PaymentMethod(ABC):
    @abstractmethod
    def pay(self, amount: float) -> bool:
        pass

class CreditCardPayment(PaymentMethod):
    def __init__(self, card_number, cvv):
        self.card_number = card_number
        self.cvv = cvv

    def pay(self, amount: float) -> bool:
        print(f"Processing Credit Card payment of ₹{amount}")
        return True

class UPIPayment(PaymentMethod):
    def __init__(self, upi_id):
        self.upi_id = upi_id

    def pay(self, amount: float) -> bool:
        print(f"Processing UPI payment of ₹{amount} via {self.upi_id}")
        return True

class WalletPayment(PaymentMethod):
    def __init__(self, wallet_name, balance):
        self.wallet_name = wallet_name
        self.balance = balance

    def pay(self, amount: float) -> bool:
        if self.balance >= amount:
            self.balance -= amount
            print(f"Processed {self.wallet_name} payment of ₹{amount}")
            return True
        print("Insufficient wallet balance")
        return False

class PaymentFactory:
    @staticmethod
    def create_payment(method: str, **kwargs):
        payment_methods = {
            "credit_card": CreditCardPayment,
            "upi": UPIPayment,
            "wallet": WalletPayment
        }
        payment_class = payment_methods.get(method.lower())
        if payment_class:
            return payment_class(**kwargs)
        raise ValueError(f"Unknown payment method: {method}")

# ==================== OBSERVER PATTERN ====================
# Requirement: Send notifications after payment

class Observer(ABC):
    @abstractmethod
    def update(self, message: str):
        pass

class EmailNotification(Observer):
    def __init__(self, email):
        self.email = email

    def update(self, message: str):
        print(f"[EMAIL to {self.email}]: {message}")

class SMSNotification(Observer):
    def __init__(self, phone):
        self.phone = phone

    def update(self, message: str):
        print(f"[SMS to {self.phone}]: {message}")

class PaymentSubject:
    def __init__(self):
        self.observers: List[Observer] = []

    def attach(self, observer: Observer):
        self.observers.append(observer)

    def detach(self, observer: Observer):
        self.observers.remove(observer)

    def notify_all(self, message: str):
        for observer in self.observers:
            observer.update(message)

# ==================== MAIN PAYMENT SYSTEM ====================

class PaymentProcessor(PaymentSubject):
    def __init__(self, discount_strategy: DiscountStrategy):
        super().__init__()
        self.discount_strategy = discount_strategy

    def process_payment(self, amount: float, payment_method: PaymentMethod) -> bool:
        # Apply discount
        final_amount = self.discount_strategy.calculate(amount)
        print(f"Original: ₹{amount}, After Discount: ₹{final_amount}")

        # Process payment
        success = payment_method.pay(final_amount)

        if success:
            self.notify_all(f"Payment of ₹{final_amount} successful!")

        return success

# Demonstration
print("=== Payment with Credit Card (Regular Customer) ===")
processor = PaymentProcessor(RegularCustomerDiscount())
processor.attach(EmailNotification("user@email.com"))
processor.attach(SMSNotification("+91-9876543210"))
payment = PaymentFactory.create_payment("credit_card", card_number="1234", cvv="123")
processor.process_payment(10000, payment)

print("\n=== Payment with UPI (Premium Customer) ===")
processor2 = PaymentProcessor(PremiumCustomerDiscount())
processor2.attach(EmailNotification("premium@email.com"))
payment2 = PaymentFactory.create_payment("upi", upi_id="user@upi")
processor2.process_payment(10000, payment2)
